#include <bits/stdc++.h>
using namespace std;
int main(){
    string s;
    cin>>s;
    if(s.size()==1){
    	cout<<s[0];
    	return 0;
	}
    if(s[0]=='-'){
        for(int i=1;i<s.size()/2;i++){
            swap(s[i],s[s.size()-i]);
        }
        cout<<"-";
        bool flag=true;
        for(int i=1;i<s.size();i++){
            if(flag && s[i]=='0')continue;
            else{
                cout<<s[i];
                flag=false;
            }
        }
    }else{
        for(int i=0;i<s.size()/2;i++){
            swap(s[i],s[s.size()-i-1]);
        }
        bool flag=true;
        for(int i=0;i<s.size();i++){
            if(flag && s[i]=='0')continue;
            else{
                cout<<s[i];
                flag=false;
            }
        }
    }
    return 0;
}
